import { useState } from "react";
import React from "react";
const API_URL = "https://script.google.com/macros/s/AKfycbwGFAziWwkvabxXzRHTt_EM8Nu7EB6PmH2zAeoo7caq5tNTPtbSOCDOx05Wtvwk9hfaAA/exec";
const LOGO_SRC = "data:image/png;base64,";

const sessions = [];
const participants = [];

export default function App() {
  const [screen, setScreen] = useState("login");
  const [user, setUser] = useState(null);
const [sessions, setSessions] = useState([]);
const [participants, setParticipants] = useState([]);
const [loading, setLoading] = useState(true);

React.useEffect(() => {
  fetch(`${API_URL}?action=getSessions`)
    .then(res => res.json())
    .then(data => {
      setSessions(data);
      setLoading(false);
    })
    .catch(err => {
      console.error("Erreur chargement sessions:", err);
      setLoading(false);
    });
}, []);

const loadParticipants = (sessionId) => {
  fetch(`${API_URL}?action=getParticipants&sessionId=${sessionId}`)
    .then(res => res.json())
    .then(data => setParticipants(data));
};
  const [selectedSession, setSelectedSession] = useState(null);
  const [likes, setLikes] = useState({}); // { id: "love" | "friend" }
  const [resultsData, setResultsData] = useState(null); // { matches, pending }
  const [pendingResponses, setPendingResponses] = useState({}); // { id: "accepted" | "refused" }
  const [likeAnim, setLikeAnim] = useState(null);

  
  const handleLike = (p, type) => {
    // Allow changing: if same type clicked again, deselect
    if (likes[p.id] === type) {
      setLikes((prev) => { const n = {...prev}; delete n[p.id]; return n; });
      return;
    }
    setLikes((prev) => ({ ...prev, [p.id]: type }));
    setLikeAnim(p.id);
    setTimeout(() => setLikeAnim(null), 700);
  };

  const handleValidate = () => {
    const likesArray = Object.entries(likes).map(([id, type]) => {
      const p = participants.find(x => x.id === parseInt(id));
      return { toEmail: p ? p.email : "", type: type };
    });

    fetch(`${API_URL}?action=saveLikes&fromEmail=${encodeURIComponent(user.email)}&sessionId=${selectedSession.id}&likes=${encodeURIComponent(JSON.stringify(likesArray))}`)
      .then(res => res.json())
      .then(() => {
        fetch(`${API_URL}?action=getResults&email=${encodeURIComponent(user.email)}&sessionId=${selectedSession.id}`)
          .then(res => res.json())
          .then(data => {
            setResultsData(data);
            setScreen("results");
          });
      });
  };

  const css = `
    @keyframes fadeUp { from { opacity:0; transform:translateY(20px); } to { opacity:1; transform:translateY(0); } }
    @keyframes heartPop { 0% { transform:scale(1); } 50% { transform:scale(1.5); } 100% { transform:scale(1); } }
    @keyframes matchReveal { from { opacity:0; transform:scale(0.8); } to { opacity:1; transform:scale(1); } }
    @keyframes bgShift {
      0%   { background-position: 0% 50%; }
      50%  { background-position: 100% 50%; }
      100% { background-position: 0% 50%; }
    }
    @keyframes floatHeart {
      0%   { transform: translateY(0) scale(1) rotate(0deg); opacity: 1; }
      80%  { opacity: 0.6; }
      100% { transform: translateY(-680px) scale(0.3) rotate(20deg); opacity: 0; }
    }
    @keyframes sway {
      0%,100% { margin-left: 0px; }
      25%      { margin-left: 18px; }
      75%      { margin-left: -18px; }
    }
    .fade-up { animation: fadeUp 0.5s ease both; }
    .heart-pop { animation: heartPop 0.4s ease; }
    .match-reveal { animation: matchReveal 0.6s cubic-bezier(0.34, 1.56, 0.64, 1) both; }
    ::-webkit-scrollbar { width: 0; }
    @keyframes pulse {
      0%, 100% { opacity: 1; }
      50%       { opacity: 0.55; }
    }
    .heart-bubble {
      position: absolute;
      bottom: 70px;
      animation: floatHeart 3.5s ease-in forwards, sway 1.2s ease-in-out infinite;
      pointer-events: none;
      font-size: 22px;
      z-index: 10;
    }
    .btn-pulse {
      animation: pulse 2s ease-in-out infinite;
    }
  `;

  return (
    <div style={{ display: "flex", justifyContent: "center", alignItems: "center", minHeight: "100vh", background: "linear-gradient(135deg, #1a0008 0%, #0d0d0f 50%, #0a0a1a 100%)", padding: 24 }}>
      <style>{css}</style>
      <div style={{ width: 390, height: 780, background: "#0D0D0F", borderRadius: 44, overflow: "hidden", fontFamily: "'Georgia', serif", boxShadow: "0 40px 100px rgba(0,0,0,0.6), inset 0 0 0 1px rgba(255,255,255,0.08)", display: "flex", flexDirection: "column" }}>
        <div style={{ padding: "14px 28px 0", display: "flex", justifyContent: "space-between", color: "rgba(255,255,255,0.6)", fontSize: 12, fontFamily: "sans-serif", flexShrink: 0 }}>
          <span>9:41</span><span>●●●</span>
        </div>
        <div style={{ flex: 1, overflow: "hidden", display: "flex", flexDirection: "column" }}>
          {screen === "login" && <LoginScreen onLogin={(u) => { setUser(u); setScreen("sessions"); }} />}
          {screen === "welcome" && <WelcomeScreen onEnter={() => setScreen("sessions")} />}
          {screen === "sessions" && <SessionsScreen sessions={sessions} onSelect={(s) => { setSelectedSession(s); loadParticipants(s.id); setScreen("participants"); }} onBack={() => setScreen("login")} />}
          {screen === "participants" && <ParticipantsScreen session={selectedSession} participants={participants} likes={likes} likeAnim={likeAnim} onLike={handleLike} onValidate={handleValidate} onBack={() => { setLikes({}); setSelectedSession(null); setScreen("sessions"); }} />}
          {screen === "results" && resultsData && <ResultsScreen resultsData={resultsData} pendingResponses={pendingResponses} onRespond={(id, resp) => setPendingResponses(prev => ({...prev, [id]: resp}))} onFinish={() => setScreen("thankyou")} />}
          {screen === "thankyou" && <ThankYouScreen />}
        </div>
      </div>
    </div>
  );
}

function ProgressBar({ step }) {
  const steps = ["Session", "Likes", "Résultats"];
  return (
    <div style={{ padding: "10px 24px 0", flexShrink: 0 }}>
      <div style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: 0 }}>
        {steps.map((label, i) => {
          const num = i + 1;
          const active = num === step;
          const done = num < step;
          return (
            <React.Fragment key={i}>
              <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 3 }}>
                <div style={{
                  width: 24, height: 24, borderRadius: "50%",
                  background: done ? "#E8748A" : active ? "linear-gradient(135deg, #E8748A, #C94060)" : "rgba(255,255,255,0.1)",
                  border: active ? "none" : done ? "none" : "1px solid rgba(255,255,255,0.2)",
                  display: "flex", alignItems: "center", justifyContent: "center",
                  fontSize: 11, color: done || active ? "#fff" : "rgba(255,255,255,0.3)",
                  fontFamily: "sans-serif", fontWeight: "bold", transition: "all 0.3s"
                }}>
                  {done ? "✓" : num}
                </div>
                <div style={{
                  fontSize: 9, fontFamily: "sans-serif", letterSpacing: 0.5,
                  color: active ? "#E8748A" : done ? "rgba(255,255,255,0.6)" : "rgba(255,255,255,0.25)",
                  transition: "all 0.3s"
                }}>{label}</div>
              </div>
              {i < steps.length - 1 && (
                <div style={{
                  height: 2, width: 48, marginBottom: 14,
                  background: done ? "#E8748A" : "rgba(255,255,255,0.1)",
                  transition: "all 0.3s"
                }} />
              )}
            </React.Fragment>
          );
        })}
      </div>
    </div>
  );
}

function LoginScreen({ onLogin }) {
  const [firstName, setFirstName] = React.useState("");
  const [lastName, setLastName] = React.useState("");
  const [email, setEmail] = React.useState("");
  const [error, setError] = React.useState("");
  const [rgpd, setRgpd] = React.useState(false);

  const inputStyle = {
    width: "100%", background: "rgba(255,255,255,0.12)", border: "1px solid rgba(232,116,138,0.4)",
    borderRadius: 4, padding: "11px 14px", color: "#fff", fontSize: 13, fontFamily: "sans-serif",
    outline: "none", boxSizing: "border-box"
  };

  const handleSubmit = () => {
    if (!firstName.trim() || !lastName.trim() || !email.trim()) {
      setError("Veuillez remplir tous les champs.");
      return;
    }
    if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
      setError("Adresse email invalide.");
      return;
    }
    if (!rgpd) {
      setError("Veuillez accepter la politique de confidentialité pour continuer.");
      return;
    }
    setError("");
    onLogin({ firstName: firstName.trim(), lastName: lastName.trim(), email: email.trim() });
  };

  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center",
      padding: 32, gap: 20, position: "relative", overflow: "hidden",
      background: "linear-gradient(135deg, #2d0015, #1a0030, #2d0015)", backgroundSize: "400% 400%", animation: "bgShift 8s ease infinite" }}>
      <div style={{ position: "absolute", inset: 0, background: "radial-gradient(ellipse at 30% 60%, rgba(232,116,138,0.18) 0%, transparent 60%)", pointerEvents: "none" }} />

      <div className="fade-up" style={{ textAlign: "center", position: "relative", zIndex: 1 }}>
        <img src={LOGO_SRC} alt="Dating Romance" style={{ width: 110, height: "auto", display: "block", margin: "0 auto" }} />
        <div style={{ marginTop: 8, color: "#fff", fontSize: 12, fontFamily: "sans-serif", opacity: 0.75, textAlign: "center", maxWidth: 240, margin: "8px auto 0", lineHeight: 1.5 }}>
          Speed Dating et Soirées Dansantes pour célibataires dans des lieux élégants.
        </div>
        <div style={{ marginTop: 10, color: "rgba(255,255,255,0.45)", fontSize: 11, fontFamily: "sans-serif", opacity: 0.85, textAlign: "center" }}>
          Identifiez-vous pour accéder à votre session
        </div>
        <div style={{ marginTop: 6, color: "rgba(255,255,255,0.3)", fontSize: 11, fontFamily: "sans-serif", lineHeight: 1.6, textAlign: "center", padding: "0 4px" }}>
          Retrouvez les participants de votre session de Speed Dating, likez ceux qui vous intéressent et découvrez vos matchs.
        </div>
      </div>

      <div className="fade-up" style={{ animationDelay: "0.2s", width: "100%", position: "relative", zIndex: 1, display: "flex", flexDirection: "column", gap: 12 }}>
        <div>
          <div style={{ color: "rgba(255,255,255,0.7)", fontSize: 10, fontFamily: "sans-serif", letterSpacing: 2, textTransform: "uppercase", marginBottom: 6 }}>Prénom</div>
          <input
            type="text" placeholder="Votre prénom" value={firstName}
            onChange={e => setFirstName(e.target.value)}
            style={inputStyle}
          />
        </div>
        <div>
          <div style={{ color: "rgba(255,255,255,0.7)", fontSize: 10, fontFamily: "sans-serif", letterSpacing: 2, textTransform: "uppercase", marginBottom: 6 }}>Nom</div>
          <input
            type="text" placeholder="Votre nom" value={lastName}
            onChange={e => setLastName(e.target.value)}
            style={inputStyle}
          />
        </div>
        <div>
          <div style={{ color: "rgba(255,255,255,0.7)", fontSize: 10, fontFamily: "sans-serif", letterSpacing: 2, textTransform: "uppercase", marginBottom: 6 }}>Adresse email</div>
          <input
            type="email" placeholder="votre@email.com" value={email}
            onChange={e => setEmail(e.target.value)}
            style={inputStyle}
          />
        </div>

        {/* RGPD */}
        <div style={{ display: "flex", alignItems: "flex-start", gap: 10 }}>
          <input
            type="checkbox"
            id="rgpd"
            checked={rgpd}
            onChange={e => setRgpd(e.target.checked)}
            style={{ marginTop: 2, accentColor: "#E8748A", cursor: "pointer", flexShrink: 0 }}
          />
          <label htmlFor="rgpd" style={{ color: "rgba(255,255,255,0.45)", fontSize: 11, fontFamily: "sans-serif", lineHeight: 1.5, cursor: "pointer" }}>
            J'accepte que mes données personnelles (prénom, nom, adresse email) soient utilisées uniquement dans le cadre de cet événement Dating Romance, conformément au RGPD. Ces données ne seront ni vendues ni transmises à des tiers.
          </label>
        </div>

        {error && (
          <div style={{ color: "#E8748A", fontSize: 12, fontFamily: "sans-serif", textAlign: "center" }}>{error}</div>
        )}

        <div style={{ display: "flex", justifyContent: "center", marginTop: 4 }}>
          <button onClick={handleSubmit} className="btn-pulse"
            style={{ width: "75%", background: "linear-gradient(135deg, #E8748A, #C94060)", border: "none", borderRadius: 4, padding: "12px 0", color: "#fff", fontSize: 13, fontFamily: "sans-serif", fontWeight: "bold", cursor: "pointer" }}>
            Accéder à ma session →
          </button>
        </div>
      </div>

      <div style={{ position: "absolute", bottom: 14, left: 0, right: 0, textAlign: "center", zIndex: 2, pointerEvents: "none" }}>
        <span style={{ color: "rgba(255,255,255,0.25)", fontSize: 10, fontFamily: "sans-serif", letterSpacing: 0.5 }}>
          Dating Romance © 2026 — Tous droits réservés
        </span>
      </div>
    </div>
  );
}

function WelcomeScreen({ onEnter }) {
  const [bubbles, setBubbles] = React.useState([]);
  const heartsRef = React.useRef(null);

  React.useEffect(() => {
    const emojis = ["❤️","💕","💖","💗","💓","💝","🩷"];
    const interval = setInterval(() => {
      const id = Date.now() + Math.random();
      const left = 30 + Math.random() * 40;
      const emoji = emojis[Math.floor(Math.random() * emojis.length)];
      const duration = 3 + Math.random() * 1.5;
      setBubbles(prev => [...prev.slice(-18), { id, left, emoji, duration }]);
      setTimeout(() => setBubbles(prev => prev.filter(b => b.id !== id)), (duration + 0.5) * 1000);
    }, 400);
    return () => clearInterval(interval);
  }, []);

  return (
    <div style={{
      flex: 1, display: "flex", flexDirection: "column", alignItems: "center",
      justifyContent: "center", padding: 32, gap: 20, position: "relative", overflow: "hidden",
      background: "linear-gradient(135deg, #2d0015, #1a0030, #2d0015, #3d0020, #1a0030)",
      backgroundSize: "400% 400%",
      animation: "bgShift 8s ease infinite"
    }}>

      {/* Animated mesh overlay */}
      <div style={{ position: "absolute", inset: 0, background: "radial-gradient(ellipse at 30% 60%, rgba(232,116,138,0.18) 0%, transparent 60%), radial-gradient(ellipse at 70% 30%, rgba(160,40,100,0.15) 0%, transparent 60%)", pointerEvents: "none" }} />

      {/* Floating heart bubbles */}
      {bubbles.map(b => (
        <span key={b.id} className="heart-bubble" style={{ left: `${b.left}%`, animationDuration: `${b.duration}s, 1.2s` }}>
          {b.emoji}
        </span>
      ))}

      {/* Content */}
      <div className="fade-up" style={{ textAlign: "center", position: "relative", zIndex: 2 }}>
        <img src={LOGO_SRC} alt="Dating Romance" style={{ width: 110, height: "auto", display: "block", margin: "0 auto" }} />
        <div style={{ marginTop: 8, color: "#fff", fontSize: 12, fontFamily: "sans-serif", letterSpacing: 0.3, opacity: 0.85, textAlign: "center", maxWidth: 240, margin: "8px auto 0" }}>
          Speed Dating et Soirées Dansantes pour célibataires dans des lieux élégants.
        </div>
      </div>

      <div className="fade-up" style={{ animationDelay: "0.3s", background: "rgba(0,0,0,0.35)", border: "1px solid rgba(232,116,138,0.3)", borderRadius: 16, padding: "14px 20px", textAlign: "center", position: "relative", zIndex: 2, backdropFilter: "blur(8px)" }}>
        <p style={{ color: "rgba(255,255,255,0.85)", fontSize: 13, lineHeight: 1.6, margin: 0, fontFamily: "sans-serif" }}>
          Retrouvez les participants de votre session de Speed Dating, likez ceux qui vous intéressent et découvrez vos matchs.
        </p>
        <div style={{ marginTop: 14, display: "flex", justifyContent: "center" }}>
          <button onClick={onEnter} className="btn-pulse" style={{ background: "linear-gradient(135deg, #E8748A, #C94060)", border: "none", borderRadius: 4, padding: "11px 24px", color: "#fff", fontSize: 13, fontFamily: "sans-serif", fontWeight: "bold", cursor: "pointer" }}>
            Accéder à ma session →
          </button>
        </div>
      </div>

      {/* Launcher glow at bottom */}
      <div style={{ position: "absolute", bottom: 0, left: 0, right: 0, height: 80, background: "linear-gradient(to top, rgba(232,116,138,0.15), transparent)", pointerEvents: "none", zIndex: 1 }} />

      {/* Copyright */}
      <div style={{ position: "absolute", bottom: 14, left: 0, right: 0, textAlign: "center", zIndex: 3, pointerEvents: "none" }}>
        <span style={{ color: "rgba(255,255,255,0.35)", fontSize: 10, fontFamily: "sans-serif", letterSpacing: 0.5 }}>
          Dating Romance © 2026 — Tous droits réservés
        </span>
      </div>
    </div>
  );
}

function SessionsScreen({ sessions, onSelect, onBack }) {
  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden" }}>
      <ProgressBar step={1} />
      <div style={{ padding: "12px 24px 16px" }}>
        <button onClick={onBack} style={{ background: "none", border: "none", color: "#E8748A", fontSize: 13, fontFamily: "sans-serif", cursor: "pointer", padding: 0, marginBottom: 8, display: "block" }}>← Retour</button>
        <div style={{ color: "#E8748A", fontSize: 10, letterSpacing: 5, textTransform: "uppercase", fontFamily: "sans-serif", marginBottom: 4 }}>{sessions[0].city} — {sessions[0].month}</div>
        <div style={{ color: "#fff", fontSize: 20, whiteSpace: "nowrap" }}>Choisissez votre session</div>
      </div>
      <div style={{ flex: 1, overflowY: "auto", padding: "0 24px 24px", display: "flex", flexDirection: "column", gap: 12 }}>
        {sessions.map((s, i) => (
          <div key={s.id} className="fade-up" onClick={() => onSelect(s)}
            style={{ animationDelay: `${i * 0.1}s`, background: "rgba(255,255,255,0.04)", border: "1px solid rgba(232,116,138,0.15)", borderRadius: 20, padding: "18px 20px", cursor: "pointer", transition: "all 0.2s" }}
            onMouseEnter={e => e.currentTarget.style.background = "rgba(232,116,138,0.08)"}
            onMouseLeave={e => e.currentTarget.style.background = "rgba(255,255,255,0.04)"}>
            <div style={{ display: "flex", justifyContent: "space-between" }}>
              <div>
                <div style={{ color: "#E8748A", fontSize: 11, fontFamily: "sans-serif", letterSpacing: 1, marginBottom: 4 }}>{s.date}</div>
                <div style={{ color: "#fff", fontSize: 18, marginBottom: 4 }}>{s.time}</div>
                <div style={{ color: "rgba(255,255,255,0.5)", fontSize: 13, fontFamily: "sans-serif" }}>{s.age}</div>
              </div>
              <div style={{ textAlign: "right" }}>
                <div style={{ color: "#fff", fontSize: 22 }}>{s.spots}</div>
                <div style={{ color: "rgba(255,255,255,0.4)", fontSize: 11, fontFamily: "sans-serif" }}>participants</div>
              </div>
            </div>
          </div>
        ))}

        <div style={{ marginTop: 8, background: "rgba(232,116,138,0.15)", border: "2px solid rgba(232,116,138,0.6)", borderRadius: 12, padding: "12px 16px" }}>
          <div style={{ color: "#E8748A", fontSize: 11, fontFamily: "sans-serif", fontWeight: "bold", letterSpacing: 1, textTransform: "uppercase", textAlign: "center", marginBottom: 6 }}>
            ⚠️ Important
          </div>
          <p style={{ color: "#fff", fontSize: 12, fontFamily: "sans-serif", lineHeight: 1.6, margin: 0, textAlign: "center" }}>
            Veillez à choisir la bonne session. Si vous sélectionnez une session incorrecte, vos likes ne seront pas comptabilisés et vous ne pourrez pas obtenir de matchs.
          </p>
        </div>
      </div>
    </div>
  );
}

function ParticipantsScreen({ session, participants, likes, likeAnim, onLike, onValidate, onBack }) {
  const likedCount = Object.keys(likes).length;
  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden" }}>
      <ProgressBar step={2} />
      <div style={{ padding: "8px 24px 12px", borderBottom: "1px solid rgba(255,255,255,0.06)" }}>
        <button onClick={onBack} style={{ background: "none", border: "none", color: "#E8748A", fontSize: 13, fontFamily: "sans-serif", cursor: "pointer", padding: 0, marginBottom: 8 }}>← Retour</button>
        <div style={{ display: "flex", alignItems: "baseline", gap: 10, marginBottom: 4, flexWrap: "wrap" }}>
          <div style={{ color: "#fff", fontSize: 12, fontFamily: "sans-serif" }}>{session.time}</div>
          <div style={{ color: "#E8748A", fontSize: 12, fontFamily: "sans-serif" }}>{session.date} · {session.city}</div>
          <div style={{ color: "rgba(255,255,255,0.45)", fontSize: 12, fontFamily: "sans-serif" }}>{session.age}</div>
        </div>
        {/* Legend */}
        <div style={{ display: "flex", gap: 8, marginBottom: 6, marginTop: 4 }}>
          <div style={{ flex: 1, background: "rgba(232,116,138,0.12)", border: "1px solid rgba(232,116,138,0.4)", borderRadius: 6, padding: "5px 10px", display: "flex", alignItems: "center", gap: 6 }}>
            <span style={{ fontSize: 15 }}>❤️</span>
            <span style={{ color: "#fff", fontSize: 11, fontFamily: "sans-serif", fontWeight: "bold" }}>Plus que de l'amitié</span>
          </div>
          <div style={{ flex: 1, background: "rgba(100,200,100,0.1)", border: "1px solid rgba(100,200,100,0.35)", borderRadius: 6, padding: "5px 10px", display: "flex", alignItems: "center", gap: 6 }}>
            <span style={{ fontSize: 15 }}>💚</span>
            <span style={{ color: "#fff", fontSize: 11, fontFamily: "sans-serif", fontWeight: "bold" }}>Amitié</span>
          </div>
        </div>
        <div style={{ color: "rgba(255,255,255,0.35)", fontSize: 11, fontFamily: "sans-serif" }}>{likedCount} like{likedCount > 1 ? "s" : ""} envoyé{likedCount > 1 ? "s" : ""}</div>
      </div>
      <div style={{ flex: 1, overflowY: "auto", padding: "8px 16px", display: "grid", gridTemplateColumns: "1fr 1fr", gridAutoRows: "100px", gap: 8, alignContent: "start" }}>
        {participants.map((p, i) => (
          <div key={p.id} className="fade-up" style={{ animationDelay: `${i * 0.08}s`, background: "rgba(255,255,255,0.04)", border: `1px solid ${likes[p.id] === "love" ? "rgba(232,116,138,0.6)" : likes[p.id] === "friend" ? "rgba(100,200,100,0.5)" : "rgba(255,255,255,0.07)"}`, borderRadius: 10, overflow: "hidden", transition: "all 0.2s", display: "flex", flexDirection: "column", height: "100px" }}>
            <div style={{ padding: "7px 10px 4px", flex: 1 }}>
              <div style={{ color: "#fff", fontSize: 12, fontWeight: "500", whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>{p.prenom} {p.nom ? p.nom.substring(0,2)+"." : ""}</div>
                          </div>
            <div style={{ display: "flex", borderTop: "1px solid rgba(255,255,255,0.06)", flexShrink: 0 }}>
              <button
                onClick={() => onLike(p, "love")}
                className={likeAnim === p.id && likes[p.id] === "love" ? "heart-pop" : ""}
                style={{ flex: 1, background: likes[p.id] === "love" ? "rgba(232,116,138,0.3)" : "transparent", border: likes[p.id] === "love" ? "none" : "none", borderRight: "1px solid rgba(255,255,255,0.06)", padding: "5px 0", cursor: "pointer", fontSize: 14, opacity: likes[p.id] === "friend" ? 0.35 : 1 }}
              >❤️</button>
              <button
                onClick={() => onLike(p, "friend")}
                className={likeAnim === p.id && likes[p.id] === "friend" ? "heart-pop" : ""}
                style={{ flex: 1, background: likes[p.id] === "friend" ? "rgba(100,200,100,0.25)" : "transparent", border: "none", padding: "5px 0", cursor: "pointer", fontSize: 14, opacity: likes[p.id] === "love" ? 0.35 : 1 }}
              >💚</button>
            </div>
          </div>
        ))}
      </div>

      {/* Validate button */}
      <div style={{ padding: "10px 16px", borderTop: "1px solid rgba(255,255,255,0.06)", flexShrink: 0, display: "flex", justifyContent: "center" }}>
        <button
          onClick={onValidate}
          disabled={Object.keys(likes).length === 0}
          className={Object.keys(likes).length > 0 ? "btn-pulse" : ""}
          style={{ width: "75%", background: Object.keys(likes).length === 0 ? "rgba(255,255,255,0.06)" : "linear-gradient(135deg, #E8748A, #C94060)", border: "none", borderRadius: 4, padding: "11px 0", color: Object.keys(likes).length === 0 ? "rgba(255,255,255,0.3)" : "#fff", fontSize: 13, fontFamily: "sans-serif", fontWeight: "bold", cursor: Object.keys(likes).length === 0 ? "default" : "pointer", transition: "all 0.3s" }}
        >
          Valider mes choix ({Object.keys(likes).length} like{Object.keys(likes).length > 1 ? "s" : ""}) →
        </button>
      </div>
    </div>
  );
}

function ResultsScreen({ resultsData, pendingResponses, onRespond, onFinish }) {
  const { matches, pending } = resultsData;
  const unanswered = pending.filter(p => !pendingResponses[p.id]);
  const answered = pending.filter(p => pendingResponses[p.id]);

  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden", background: "#0D0D0F" }}>
      {/* Header */}
      <ProgressBar step={3} />
      <div style={{ padding: "8px 24px 12px", borderBottom: "1px solid rgba(255,255,255,0.06)", flexShrink: 0 }}>
        <div style={{ color: "#fff", fontSize: 18 }}>Vos résultats</div>
      </div>

      <div style={{ flex: 1, overflowY: "auto", padding: "16px 20px", display: "flex", flexDirection: "column", gap: 20 }}>

        {/* MATCHES */}
        <div>
          <div style={{ color: "#E8748A", fontSize: 10, letterSpacing: 4, textTransform: "uppercase", fontFamily: "sans-serif", marginBottom: 10 }}>
            💘 Matchs ({matches.length})
          </div>
          {matches.length === 0 ? (
            <div style={{ color: "rgba(255,255,255,0.35)", fontSize: 13, fontFamily: "sans-serif", fontStyle: "italic" }}>Aucun match pour cette session.</div>
          ) : (
            <>
              <div style={{ background: "rgba(232,116,138,0.08)", border: "1px solid rgba(232,116,138,0.2)", borderRadius: 10, padding: "10px 14px", marginBottom: 10 }}>
                <p style={{ color: "rgba(255,255,255,0.7)", fontSize: 12, fontFamily: "sans-serif", lineHeight: 1.6, margin: 0 }}>
                  📧 Les coordonnées de vos matchs vous ont été envoyées par email. Pensez à vérifier vos spams.
                </p>
              </div>
              {matches.map(p => (
                <div key={p.id} style={{ background: "rgba(232,116,138,0.06)", border: "1px solid rgba(232,116,138,0.25)", borderRadius: 10, padding: "10px 14px", marginBottom: 8, display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                  <div>
                    <div style={{ color: "#fff", fontSize: 13, fontWeight: "bold" }}>{p.prenom} {p.nom ? p.nom.substring(0,2)+"." : ""}</div>

                  </div>
                  <div style={{ fontSize: 20 }}>💘</div>
                </div>
              ))}
            </>
          )}
        </div>

        {/* PENDING LIKES RECEIVED */}
        {unanswered.length > 0 && (
          <div>
            <div style={{ color: "rgba(255,255,255,0.6)", fontSize: 10, letterSpacing: 4, textTransform: "uppercase", fontFamily: "sans-serif", marginBottom: 10 }}>
              💌 Quelqu'un vous a liké ({unanswered.length})
            </div>
            {unanswered.map(p => (
              <div key={p.id} style={{ background: "rgba(255,255,255,0.04)", border: "1px solid rgba(255,255,255,0.08)", borderRadius: 10, padding: "10px 14px", marginBottom: 8 }}>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 8 }}>
                  <div>
                    <div style={{ color: "#fff", fontSize: 13, fontWeight: "bold" }}>{p.prenom} {p.nom ? p.nom.substring(0,2)+"." : ""}</div>
                    <div style={{ color: "rgba(255,255,255,0.4)", fontSize: 11, fontFamily: "sans-serif", marginTop: 2 }}>
                       ·  · {p.theirType === "love" ? "❤️ Plus que de l'amitié" : "💚 Amitié"}
                    </div>
                  </div>
                </div>
                <div style={{ display: "flex", gap: 8 }}>
                  <button onClick={() => onRespond(p.id, "accepted")}
                    style={{ flex: 1, background: "linear-gradient(135deg, #E8748A, #C94060)", border: "none", borderRadius: 4, padding: "8px 0", color: "#fff", fontSize: 12, fontFamily: "sans-serif", fontWeight: "bold", cursor: "pointer" }}>
                    ✓ Accepter
                  </button>
                  <button onClick={() => onRespond(p.id, "refused")}
                    style={{ flex: 1, background: "rgba(255,255,255,0.06)", border: "1px solid rgba(255,255,255,0.1)", borderRadius: 4, padding: "8px 0", color: "rgba(255,255,255,0.5)", fontSize: 12, fontFamily: "sans-serif", cursor: "pointer" }}>
                    ✕ Refuser
                  </button>
                </div>
              </div>
            ))}

            {/* Info + validate */}
            <div style={{ background: "rgba(255,255,255,0.03)", border: "1px solid rgba(255,255,255,0.07)", borderRadius: 10, padding: "10px 14px", marginBottom: 12 }}>
              <p style={{ color: "rgba(255,255,255,0.5)", fontSize: 11, fontFamily: "sans-serif", lineHeight: 1.6, margin: 0 }}>
                ℹ️ Si vous acceptez un like reçu, vos coordonnées et celles de cette personne seront automatiquement partagées par email — chacun recevra les coordonnées de l'autre.
              </p>
            </div>

          </div>
        )}

        {/* ANSWERED */}
        {answered.length > 0 && (
          <div>
            <div style={{ color: "rgba(255,255,255,0.3)", fontSize: 10, letterSpacing: 4, textTransform: "uppercase", fontFamily: "sans-serif", marginBottom: 10 }}>Réponses données</div>
            {answered.map(p => (
              <div key={p.id} style={{ marginBottom: 8 }}>
                <div style={{ background: "rgba(255,255,255,0.02)", border: `1px solid ${pendingResponses[p.id] === "accepted" ? "rgba(232,116,138,0.2)" : "rgba(255,255,255,0.05)"}`, borderRadius: 10, padding: "10px 14px", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                  <div>
                    <div style={{ color: "rgba(255,255,255,0.5)", fontSize: 13 }}>{p.prenom} {p.nom ? p.nom.substring(0,2)+"." : ""}</div>

                  </div>
                  <div style={{ fontSize: 13, fontFamily: "sans-serif", color: pendingResponses[p.id] === "accepted" ? "#E8748A" : "rgba(255,255,255,0.3)" }}>
                    {pendingResponses[p.id] === "accepted" ? "✓ Accepté" : "✕ Refusé"}
                  </div>
                </div>
                {pendingResponses[p.id] === "accepted" && (
                  <div style={{ display: "flex", alignItems: "center", gap: 6, padding: "6px 12px 0" }}>
                    <span style={{ fontSize: 11 }}>📧</span>
                    <span style={{ color: "rgba(232,116,138,0.7)", fontSize: 11, fontFamily: "sans-serif", fontStyle: "italic" }}>
                      Un email avec ses coordonnées va vous être envoyé dans les prochaines minutes.
                    </span>
                  </div>
                )}
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Finish button — pinned to bottom */}
      <div style={{ padding: "10px 16px", borderTop: "1px solid rgba(255,255,255,0.06)", flexShrink: 0, display: "flex", justifyContent: "center" }}>
        <button onClick={onFinish} className="btn-pulse"
          style={{ width: "75%", background: "linear-gradient(135deg, #E8748A, #C94060)", border: "none", borderRadius: 4, padding: "11px 0", color: "#fff", fontSize: 13, fontFamily: "sans-serif", fontWeight: "bold", cursor: "pointer" }}>
          Terminer la session →
        </button>
      </div>
    </div>
  );
}

